import importlib.util; spec = importlib.util.spec_from_file_location('m','/tmp/eval_qkv/qkv.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod)
try: mod.QuorumKV(n=5, r=2, w=3)
except ValueError: pass
else: raise AssertionError('r+w<=n must raise ValueError')
kv = mod.QuorumKV(n=5, r=3, w=3); assert kv.write('k1','v1', timestamp=1, node='A', success_replicas=[0,1,2]); assert kv.read('k1', response_replicas=[0,1,3]) == 'v1'; kv.write('k1','v2', timestamp=2, node='B', success_replicas=[2,3,4]); assert kv.read('k1', response_replicas=[0,1,4]) == 'v2'
assert kv.replica_state('k1', 0) == ('v2', 2, 'B'), f'read repair failed on replica 0: {kv.replica_state("k1", 0)}'; assert kv.replica_state('k1', 1) == ('v2', 2, 'B'), 'read repair failed on replica 1'
assert not kv.write('k2','v', timestamp=1, node='A', success_replicas=[0,1]); assert kv.replica_state('k2', 0) is None, 'failed quorum must not write'
kv.write('k3','vA', timestamp=7, node='A', success_replicas=[0,1,2]); kv.write('k3','vZ', timestamp=7, node='Z', success_replicas=[0,1,2]); assert kv.read('k3', response_replicas=[0,1,2]) == 'vZ', 'timestamp-tie must break toward lexicographically larger node'
kv.write('k3','vM', timestamp=7, node='M', success_replicas=[0,1,2]); assert kv.read('k3', response_replicas=[0,1,2]) == 'vZ', 'lower node on tie must not overwrite'
print('OK')
